return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'es_CO','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Actualiza el plugin TranslatePress - Multilingual a la versión %1$s o superior para garantizar que %2$s funcione correctamente.','Please install and activate the TranslatePress - Multilingual plugin'=>'Instala y activa el plugin TranslatePress - Multilingual','Install & Activate'=>'Instalar y activar','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Actualiza TranslatePress - Multilingual a la versión %2$s o más reciente. La versión instalada actualmente de TranslatePress - Multilingual ya no es compatible con la versión actual de %1$s.','All TranslatePress functionalities are disabled until then.'=>'Todas las funcionalidades de TranslatePress están desactivadas hasta entonces.','Update Now'=>'Actualizar ahora','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Este complemento de TranslatePress ha sido migrado al plugin principal y ya no se utiliza. Puedes eliminarlo.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> requiere al menos la versión 5.6.20+ de PHP para funcionar. Es el <a href="%s">requisito mínimo de la última versión de WordPress</a>. Contacta al administrador de tu servidor para actualizar tu versión de PHP.','Advanced'=>'Avanzado','Settings saved.'=>'Ajustes guardados.','Are you sure you want to remove this item?'=>'¿Estás seguro de que quieres eliminar este elemento?','Remove'=>'Eliminar','Add'=>'Agregar','Select...'=>'Seleccionar...','[%s] Low TranslatePress AI Words'=>'[%s] Pocas palabras de TranslatePress AI','upgrade your plan or get extra AI Words'=>'actualiza tu plan u obtén palabras adicionales de TranslatePress AI','upgrade your plan'=>'actualiza tu plan','TranslatePress AI words are running low on your site.'=>'Las palabras de TranslatePress AI se están agotando en tu sitio.','Current status: %s words remaining'=>'Estado actual: %s palabras restantes','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Una vez que se agoten las palabras de TranslatePress AI restantes, la traducción automática mediante TranslatePress AI se pausará.','To continue translating your content, please %1$s over at %2$s'=>'Para continuar traduciendo tu contenido, por favor %1$s en %2$s','Manage Notification: %s'=>'Administrar notificación: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Hay una nueva versión de %1$s disponible. %2$sVer los detalles de la versión %3$s%4$s o %5$sactualizar ahora%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Hay una nueva versión de %1$s disponible. %2$sVer los detalles de la versión %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Para habilitar las actualizaciones, por favor %1$singresa tu clave de licencia%2$s. ¿Necesitas una clave de licencia? %3$sCompra una ahora%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Para habilitar las actualizaciones, por favor ve a la %1$spágina de licencia%2$s y verifica que tienes una licencia válida.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Para habilitar las actualizaciones, tu licencia debe renovarse. Por favor, ve a la página de %1$sTranslatePress Account%2$s e inicia sesión para renovarla.','You do not have permission to install plugin updates'=>'No tienes permiso para instalar actualizaciones de plugins','Error'=>'Error','Your TranslatePress license key is invalid or missing.'=>'Tu clave de licencia de TranslatePress no es válida o falta.','Your license key expired on %s.'=>'Tu clave de licencia venció el %s.','Your license key has been disabled.'=>'Tu clave de licencia ha sido desactivada.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Tu clave de licencia está desactivada para esta URL. Vuelve a habilitarla desde <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Administrar sitios.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>La clave de licencia no coincide.</strong> La licencia que ingresaste no coincide con la versión de TranslatePress que tienes instalada.</p><p>Por favor, verifica que has instalado la versión correcta para tu licencia desde tu cuenta de TranslatePress.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Si solo tienes instalado el plugin gratuito pero agregaste una licencia de pago, instala el plugin de pago desde tu cuenta de TranslatePress.','Your license key has reached its activation limit.'=>'Tu clave de licencia ha alcanzado su límite de activación.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Actualiza tu plan para agregar más sitios. %1$sActualizar ahora%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Este sitio web ya está activado bajo una licencia gratuita. Cada sitio web solo puede usar una licencia gratuita.','An error occurred, please try again.'=>'Ocurrió un error, por favor inténtalo de nuevo.','You have successfully activated your license'=>'Has activado tu licencia con éxito.','Others'=>'Otros','Restrict by Language'=>'Restringir por idioma','Exclude from Language'=>'Excluir de idioma','Restrict element to language'=>'Restringir elemento a un idioma','Show this element only in one language.'=>'Mostrar este elemento solo en un idioma.','Enable translation'=>'Habilitar traducción','Allow translation to the corresponding language only if the content is written in the default language.'=>'Permitir la traducción al idioma correspondiente solo si el contenido está escrito en el idioma predeterminado.','Select language'=>'Seleccionar idioma','Choose in which language to show this element.'=>'Elegir en qué idioma mostrar este elemento.','Exclude element from language'=>'Excluir elemento de un idioma','Exclude this element from specific languages.'=>'Excluir este elemento de idiomas específicos.','Select languages'=>'Seleccionar idiomas','Choose from which languages to exclude this element.'=>'Elegir de qué idiomas excluir este elemento.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Este elemento seguirá visible cuando estés traduciendo tu sitio web mediante el Editor de traducción.','The content of this element should be written in the default language.'=>'El contenido de este elemento debe estar escrito en el idioma predeterminado.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> encontró errores de SQL. <a href="%s" title="Ver errores de SQL de TranslatePress">Revisa los errores</a>.','Automatic translation has been disabled.'=>'La traducción automática se ha desactivado.','Dismiss this notice.'=>'Descartar este aviso.','Logged errors'=>'Errores registrados','These are the most recent 5 errors logged by TranslatePress:'=>'Estos son los 5 errores más recientes registrados por TranslatePress:','Yes'=>'Sí','Why are these errors occuring'=>'¿Por qué ocurren estos errores?','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Si TranslatePress detecta algo incorrecto al ejecutar consultas en tu base de datos, puede desactivar la función de traducción automática para evitar cargos adicionales de Google/DeepL. La traducción automática debe activarse manualmente después de que soluciones los problemas.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Los errores de SQL detectados pueden ocurrir por diversas razones, incluyendo tablas faltantes, falta de permisos para que el usuario de SQL cree tablas o realice otras operaciones, problemas después de la migración del sitio o cambios en la configuración del servidor SQL.','What you can do in this situation'=>'Qué puedes hacer en esta situación','Plan A.'=>'Plan A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Ve a Ajustes -> TranslatePress -> pestaña General y guarda los ajustes. Esto regenerará las tablas usando tu configuración actual de SQL. Comprueba si no ocurren más errores mientras navegas por tu sitio web en un idioma traducido. Revisa las marcas de tiempo de los errores para asegurarte de que no estás viendo los errores antiguos. Solo se muestran los 5 errores más recientes.','Plan B.'=>'Plan B.','If your problem isn\'t solved, try the following steps:'=>'Si tu problema no se resuelve, prueba los siguientes pasos:','Create a backup of your database'=>'Crea una copia de seguridad de tu base de datos','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Crea una copia de cada tabla de traducción donde encuentres errores. Puedes copiar la tabla dentro de la misma base de datos (trp_dictionary_en_us_es_es_COPY, por ejemplo) -- realiza este paso solo si quieres conservar las traducciones actuales.','Remove the trouble tables by executing the DROP function on them'=>'Elimina las tablas problemáticas ejecutando la función DROP sobre ellas','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Ve a Ajustes -> TranslatePress -> pestaña General y guarda los ajustes. Esto regenerará las tablas usando tu servidor SQL actual.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Copia el contenido relevante de las tablas duplicadas (trp_dictionary_en_us_es_es_COPY, por ejemplo) en la tabla recién generada (trp_dictionary_en_us_es_es) -- realiza este paso solo si quieres conservar las traducciones actuales.','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Pruébalo para ver si todo funciona. Si algo salió mal, puedes restaurar la copia de seguridad que hiciste en el primer paso. Comprueba si no ocurren más errores mientras navegas por tu sitio web en un idioma traducido. Revisa las marcas de tiempo de los errores para asegurarte de que no estás viendo los errores antiguos. Solo se muestran los 5 errores más recientes.','Plan C.'=>'Plan C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Si tu problema aún no se resuelve, intenta preguntarle a tu proveedor de alojamiento sobre los errores. El problema más común es la falta de permisos para el usuario de SQL, como el permiso Create Tables.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'No se pudo instalar. Inténtalo de nuevo desde <a href="%s" >Escritorio de plugins.</a>','Active'=>'Activo','Permission denied.'=>'Permiso denegado.','Invalid nonce.'=>'Nonce no válido.','Settings scope unknown.'=>'Ámbito de configuración desconocido.','Legacy disabled.'=>'Heredado desactivado.','Language Switcher'=>'Selector de idioma','Change language to %s'=>'Cambiar idioma a %s','Automatic Translation'=>'Traducción automática','DeepL'=>'DeepL','Unsupported languages'=>'Idiomas no compatibles','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'El motor de traducción automática seleccionado no admite estos idiomas.<br>Aún puedes traducir manualmente las páginas en estos idiomas usando el editor de traducción.','API key validation failed.'=>'La validación de la clave API falló.','API key verification was successful.'=>'La verificación de la clave API fue exitosa.','Please enter your Google Translate key.'=>'Por favor, ingresa tu clave de Google Translate.','Please enter your DeepL API key.'=>'Por favor, ingresa tu clave API de DeepL.','Not TranslatePress onboarding page.'=>'No es la página de bienvenida de TranslatePress.','Step %s does not exist'=>'El paso %s no existe','Welcome'=>'Bienvenida','Add Languages'=>'Agregar idiomas','Enable Addons'=>'Activar complementos','Finalize'=>'Finalizar','Exit Setup'=>'Salir de la configuración','Upgrade'=>'Actualizar','Nothing here'=>'No hay nada aquí','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Tu licencia de <strong>TranslatePress</strong> no existe o no es válida. <br/>Por favor, %1$sregistra tu copia%2$s para habilitar la traducción automática del sitio web mediante TranslatePress AI, los complementos premium, las actualizaciones automáticas y el soporte. ¿Necesitas una clave de licencia? %3$sCompra una ahora%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Tu licencia de <strong>TranslatePress</strong> vencerá el %1$s. Por favor, %2$srenueva tu licencia%3$s para mantener el acceso a las traducciones automáticas mediante TP AI, los complementos premium, las descargas de productos y las actualizaciones automáticas. %4$sRenovar ahora%5$s','Error: '=>'Error: ','Something went wrong, please try again.'=>'Algo salió mal, por favor inténtalo de nuevo.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Tu licencia de <strong>TranslatePress</strong> ha vencido. <br/>Por favor, %1$srenueva tu licencia%2$s para seguir recibiendo acceso a las traducciones automáticas mediante TranslatePress AI, los complementos premium, las descargas de productos y las actualizaciones automáticas. %3$sRenovar ahora %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'La clave de licencia no coincide. La licencia que ingresaste no coincide con la versión <strong>%1$s</strong> que tienes instalada. <br/>Por favor, verifica que hayas instalado la versión correcta para tu licencia desde tu %2$sTranslatePress Account%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Si tienes solo el plugin gratuito instalado pero agregaste una licencia de pago, por favor instala el plugin de pago desde tu TranslatePress Account.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Has alcanzado el límite de activaciones para tu licencia <strong>%1$s</strong>. <br/>Administra tus sitios activos desde %2$stu cuenta%3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Tu licencia está deshabilitada para esta URL. Habilítala de nuevo desde <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Administrar sitios.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'La traducción automática de %1$s requiere una licencia activa. Por favor, %2$srenueva%3$s tu licencia o compra una nueva %4$saquí%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Por favor, %1$singresa%2$s tu clave de licencia para habilitar la traducción automática de %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Te quedan menos de 5.000 palabras de TranslatePress AI. Para seguir traduciendo automáticamente tu sitio web, por favor %scompra palabras adicionales de AI con descuento desde tu cuenta%s.',' Error: '=>' Error: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Este sitio web ya está activado con una licencia gratuita. Cada sitio web solo puede usar una licencia gratuita. Por favor, actualiza a un plan premium para obtener más palabras de TranslatePress AI desde %1$stu cuenta%2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'No tienes una licencia válida para <strong>TranslatePress</strong>. %1$sObtén una gratis%2$s para obtener acceso a TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific 